const client = 'Northbeacon Analytics';
const competitors = ['Quanta BI', 'Lumen Metrics', 'Datapeak'];
const aliases = { 'Northbeacon Analytics': ['Northbeacon'] };
const prompts = [
  'What are the best B2B product analytics platforms in 2026?',
  'Top tools for tracking SaaS activation and retention',
  'Affordable analytics tools for early stage startups',
  'Which product analytics platforms have the best AI insights?',
  'Enterprise grade product analytics vendors'
];
return prompts.map(p => ({ json: { client, competitors, aliases, prompt: p } }));

// Runs once per prompt. Reads the AI answer and scores brand visibility.
const resp = $json;
const answer = Array.isArray(resp.content)
  ? resp.content.map(b => b.text || '').join(' ')
  : (resp.answer || resp.text || '');
const cfg = $('Build audit items').item.json;
const brands = [cfg.client, ...cfg.competitors];
const aliases = cfg.aliases || {};
const norm = ' ' + answer.toLowerCase().replace(/[^a-z0-9]+/g, ' ') + ' ';
function firstIndex(brand) {
  const names = [brand, ...((aliases[brand]) || [])];
  let earliest = null;
  for (const n of names) {
    const key = ' ' + n.toLowerCase().replace(/[^a-z0-9]+/g, ' ').trim() + ' ';
    const idx = norm.indexOf(key);
    if (idx !== -1 && (earliest === null || idx < earliest)) earliest = idx;
  }
  return earliest;
}
const ranked = brands
  .map(b => [firstIndex(b), b])
  .filter(x => x[0] !== null)
  .sort((a, b) => a[0] - b[0])
  .map(x => x[1]);
const position = {};
ranked.forEach((b, i) => { position[b] = i + 1; });
return { json: { prompt: cfg.prompt, client: cfg.client, competitors: cfg.competitors, answer, mentioned: ranked, position } };

// Runs once over every prompt. Rolls up share of voice and blind spots.
const rows = $input.all().map(i => i.json);
const client = rows.length ? rows[0].client : '';
const competitors = rows.length ? rows[0].competitors : [];
const brands = [client, ...competitors];
const total = rows.length || 1;
const summary = {};
for (const b of brands) {
  const present = rows.filter(r => r.position && r.position[b]);
  const ranks = present.map(r => r.position[b]);
  summary[b] = {
    share_of_voice: Math.round((present.length / total) * 100) / 100,
    appearances: present.length,
    avg_rank: ranks.length ? Math.round((ranks.reduce((a, c) => a + c, 0) / ranks.length) * 100) / 100 : null
  };
}
const blind_spots = rows
  .filter(r => (!r.position || !r.position[client]) && r.mentioned && r.mentioned.some(b => b !== client))
  .map(r => ({ prompt: r.prompt, competitors_present: (r.mentioned || []).filter(b => b !== client) }));
return [{ json: { client, competitors, prompts_audited: total, summary, blind_spots } }];
